class ObserverAgent:
    def __init__(self, event_queue, instinct_db):
        self.queue = event_queue
        self.db = instinct_db
        self.state = 'IDLE'
        self.behavior_buffer = []

    def on_llm_response(self, response, context):
        event = {
            'timestamp': time.time(),
            'model': response.model,
            'tool_calls': response.tool_calls,
            'usage': response.usage,
            'context_snapshot': self.capture_context()
        }
        self.behavior_buffer.append(event)

        if len(self.behavior_buffer) >= 100:
            self.analyze_and_learn()

    def capture_context(self):
        return {
            'cwd': os.getcwd(),
            'files': get_recent_files(),
            'git_status': subprocess.run(['git', 'status', '--porcelain']),
            'open_files': get_open_editor_files()
        }

    def analyze_and_learn(self):
        patterns = extract_patterns(self.behavior_buffer)
        for pattern in patterns:
            instinct = self.create_instinct(pattern)
            if instinct.confidence > THRESHOLD:
                self.db.persist(instinct)
        self.behavior_buffer.clear()
