# hermes_agent/observer/agent.py
import threading
import queue
import time
from typing import Optional, Callable
from .events import NormalizedEvent, EventType
from .context import ContextCollector
from ..learning.engine import LearningEngine

class ObserverAgent:
    def __init__(
        self,
        instinct_store,  # InstinctStore instance
        batch_size: int = 100,
        batch_interval_sec: float = 60.0,
        learning_engine: Optional[LearningEngine] = None
    ):
        self.event_queue = queue.Queue(maxsize=10000)
        self.context_collector = ContextCollector()
        self.learning_engine = learning_engine or LearningEngine(instinct_store)
        self.batch_size = batch_size
        self.batch_interval = batch_interval_sec
        self._running = False
        self._daemon_thread: Optional[threading.Thread] = None
        self._flush_thread: Optional[threading.Thread] = None
        self._stats = {'events_captured': 0, 'batches_processed': 0}

    def start(self):
        self._running = True
        self._daemon_thread = threading.Thread(target=self._capture_loop, daemon=True)
        self._daemon_thread.start()
        self._flush_thread = threading.Thread(target=self._flush_loop, daemon=True)
        self._flush_thread.start()

    def stop(self):
        self._running = False
        if self._daemon_thread:
            self._daemon_thread.join(timeout=5.0)
        if self._flush_thread:
            self._flush_thread.join(timeout=5.0)
        # Final flush
        self._flush_batch()

    def on_llm_response(self, model: str, messages: list, response: dict):
        event = NormalizedEvent(
            timestamp=time.time(),
            event_type=EventType.LLM_RESPONSE,
            payload={
                'model': model,
                'message_count': len(messages),
                'response_content': str(response)[:500]
            },
            context_snapshot=self.context_collector.capture()
        )
        self._put_event(event)

    def on_tool_call(self, tool_name: str, args: dict):
        event = NormalizedEvent(
            timestamp=time.time(),
            event_type=EventType.TOOL_CALL,
            payload={'tool_name': tool_name, 'args': args},
            context_snapshot=self.context_collector.capture()
        )
        self._put_event(event)

    def on_tool_result(self, tool_name: str, result: str, success: bool):
        event = NormalizedEvent(
            timestamp=time.time(),
            event_type=EventType.TOOL_RESULT,
            payload={'tool_name': tool_name, 'success': success, 'result_length': len(str(result))},
            context_snapshot=self.context_collector.capture()
        )
        self._put_event(event)

    def _put_event(self, event: NormalizedEvent):
        try:
            self.event_queue.put_nowait(event)
            self._stats['events_captured'] += 1
        except queue.Full:
            # Drop oldest events when queue is full to maintain responsiveness
            try:
                self.event_queue.get_nowait()
                self.event_queue.put_nowait(event)
            except queue.Empty:
                pass

    def _capture_loop(self):
        while self._running:
            time.sleep(0.1)  # Light polling

    def _flush_loop(self):
        last_flush = time.time()
        while self._running:
            now = time.time()
            queue_size = self.event_queue.qsize()
            if queue_size >= self.batch_size or (now - last_flush) >= self.batch_interval:
                if queue_size > 0:
                    self._flush_batch()
                    last_flush = now
            time.sleep(1.0)

    def _flush_batch(self):
        events = []
        while True:
            try:
                events.append(self.event_queue.get_nowait())
            except queue.Empty:
                break
        if events:
            self.learning_engine.process_batch(events)
            self._stats['batches_processed'] += 1
